#include <iostream>\n#include <vector>\n#include <set>\n\nint main() {\n  int n, m;\n  std::cin >> n >> m;\n  std::vector<std::set<int>> vertex(n);\n  for (int i = 0; i < m; i++) {\n    int a, b;\n    std::cin >> a >> b;\n    a--;\n    b--;\n    vertex[a].insert(b);\n    vertex[b].insert(a);\n  }\n  for (const std::set<int>& v : vertex) {\n    std::cout << v.size() << ' ';\n  }\n  std::cout << std::endl;\n  return 0;\n}